  rclcpp::Client<tm_msgs::srv::SendScript>::SharedPtr client =
    node->create_client<tm_msgs::srv::SendScript>("send_script");
  
  std::string cmd = "PTP(\"JPP\",0,0,90,0,90,0,35,200,0,false)";
  
  send_cmd(cmd, node, client);

  rclcpp::shutdown();
  return 0;
}

